<?php if (!defined('ABSPATH')) exit; ?>
<div class="wrap sc-admin"><h1>Réglages</h1><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="shakass_save_settings"><?php wp_nonce_field('shakass_save_settings'); ?><section class="sc-card"><label>Email destinataire<input type="email" name="settings[email]" value="<?php echo esc_attr($settings['email']); ?>"></label><label>Couleur accent<input type="color" name="settings[accent]" value="<?php echo esc_attr($settings['accent']); ?>"></label><label><input type="checkbox" name="settings[dark_mode]" value="1" <?php checked(!empty($settings['dark_mode'])); ?>> Mode sombre</label><label>Texte bouton CTA<input name="settings[cta]" value="<?php echo esc_attr($settings['cta']); ?>"></label><label>Message rassurant<input name="settings[trust]" value="<?php echo esc_attr($settings['trust']); ?>"></label><label>Produit par défaut<select name="settings[default_product]"><?php foreach($products as $p) echo '<option value="'.esc_attr($p['slug']).'" '.selected($settings['default_product'],$p['slug'],false).'>'.esc_html($p['name']).'</option>'; ?></select></label></section><section class="sc-card"><h2>Outils front</h2><?php foreach(shakass_active_tools() as $key=>$label): ?><label><input type="checkbox" name="settings[tools][<?php echo esc_attr($key); ?>]" value="1" <?php checked(!empty($settings['tools'][$key])); ?>> <?php echo esc_html($label); ?></label><?php endforeach; ?></section><button class="button button-primary">Enregistrer les réglages</button></form></div>
